+        let content = if *seq.last()? == 0x07 {
+            &seq[2..seq.len().saturating_sub(1)]
+        } else if seq.len() >= 4 && seq[seq.len() - 2] == 0x1b && seq[seq.len() - 1] == b'\\' {
+            &seq[2..seq.len().saturating_sub(2)]
+        } else {
